package irvine.oeis.a085;

import irvine.math.z.Z;

/**
 * A085009 "Von Koch" sequence generated by {1,1,2}.
 * @author Sean A. Irvine
 */
public class A085009 extends A085008 {

  private Z mA = Z.ZERO;
  private long mN = 2;

  @Override
  public Z next() {
    mN += 2;
    mA = mA.add(super.next());
    return mA.add(mN);
  }
}
